A debounce function delays invoking a function until a specified time has elapsed since the last time it was called.

```javascript
// Debounce: delay invoking fn until after wait ms have elapsed since the last call.
function debounce(fn, wait = 200) {
  let timeoutId;
  return function (...args) {
    const ctx = this;
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(ctx, args), wait);
  };
}

// Example: log window size only after resize stops for 250ms.
const handleResize = debounce(() => {
  console.log('Size:', window.innerWidth, window.innerHeight);
}, 250);

window.addEventListener('resize', handleResize);
```
